import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const EventRegister = () => {
  const navigate = useNavigate();

  const [eventData, setEventData] = useState({
    event_name: '',
    event_info: '',
    event_state: 'draft', // Default state
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEventData({ ...eventData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:6000/event/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(eventData),
      });
      if (!response.ok) throw new Error('Event registration failed');
      // Reset form or handle success
      setEventData({ event_name: '', event_info: '', event_state: 'draft' });
      navigate('/eventer/manage'); // Add this line to navigate
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <label>
        Event Name:
        <input
          type="text"
          name="event_name"
          value={eventData.event_name}
          onChange={handleInputChange}
          required
        />
      </label>
      <label>
        Event Info:
        <input
          type="text"
          name="event_info"
          value={eventData.event_info}
          onChange={handleInputChange}
          required
        />
      </label>
      <label>
        Event State:
        <select
          name="event_state"
          value={eventData.event_state}
          onChange={handleInputChange}
        >
          <option value="draft">Draft</option>
          <option value="open">Open</option>
          <option value="close">Close</option>
        </select>
      </label>
      <button type="submit">Register Event</button>
    </form>
  );
};

export default EventRegister;
